const output = $json.output;
const elapsed = $json.elapsed_s;
const now = new Date();
const date = `${String(now.getDate()).padStart(2,'0')}/${String(now.getMonth()+1).padStart(2,'0')}/${now.getFullYear()}`;

let text = output
  .replace(/^### (.+)$/gm, '*$1*')
  .replace(/^## (.+)$/gm, '*$1*')
  .replace(/^# (.+)$/gm, '*$1*')
  .replace(/\*\*(.*?)\*\*/g, '*$1*')
  .replace(/^- /gm, '• ')
  .replace(/---/g, '───');

text = `📊 Weekly SWOT — ${date}\n\n${text}\n\n───\n⏱️ Gerado em ${elapsed}s via Claude Code (with memory)`;

if (text.length > 4000) {
  text = text.substring(0, 3950) + '\n\n(truncado)';
}

return [{ json: { text, number: '351913095597' } }];

const response = $input.first().json;
