// ===== HELPERS =====
function getTaskName(item) {
  const props = item.json.properties || {};
  const nameProps = ['Name', 'Task', 'Title', 'name', 'title'];
  for (const key of nameProps) {
    if (props[key] && props[key].title && Array.isArray(props[key].title) && props[key].title.length > 0) {
      return props[key].title.map(t => t.plain_text || '').join('').trim();
    }
  }
  for (const key of Object.keys(props)) {
    const p = props[key];
    if (p && p.type === 'title' && Array.isArray(p.title) && p.title.length > 0) {
      return p.title.map(t => t.plain_text || '').join('').trim();
    }
  }
  return '(sem nome)';
}

function getTags(item) {
  const props = item.json.properties || {};
  const tagProps = ['Tags', 'Tag', 'Labels'];
  for (const key of tagProps) {
    if (props[key]) {
      if (props[key].multi_select) return props[key].multi_select.map(t => t.name);
      if (props[key].select && props[key].select.name) return [props[key].select.name];
    }
  }
  return [];
}

function getDueDate(item) {
  const props = item.json.properties || {};
  const dateProps = ['Due Date', 'Due', 'Date', 'Deadline'];
  for (const key of dateProps) {
    if (props[key] && props[key].date && props[key].date.start) {
      return props[key].date.start;
    }
  }
  return '';
}

function getProjectId(item) {
  const props = item.json.properties || {};
  const projProps = ['Project', 'Projects'];
  for (const key of projProps) {
    if (props[key] && props[key].relation && props[key].relation.length > 0) {
      return props[key].relation[0].id;
    }
  }
  return '';
}

function getProjectType(item) {
  const props = item.json.properties || {};
  const typeProps = ['Type', 'Tipo', 'Category'];
  for (const key of typeProps) {
    if (props[key]) {
      if (props[key].select && props[key].select.name) return props[key].select.name;
    }
  }
  return '';
}

function getContext(tags) {
  if (tags.includes('Brasil')) return '🇧🇷';
  if (tags.includes('Portugal')) return '🇵🇹';
  return '';
}

function getDependency(tags) {
  if (tags.includes('Dependo de Terceiros')) return '⏸️';
  return '';
}

function getTodayLisbon() {
  const now = new Date();
  return new Intl.DateTimeFormat('en-CA', {
    timeZone: 'Europe/Lisbon',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit'
  }).format(now);
}

function getWeekdayLisbon(dateStr) {
  const d = new Date(dateStr + 'T12:00:00Z');
  const fmt = new Intl.DateTimeFormat('pt-PT', {
    timeZone: 'Europe/Lisbon',
    weekday: 'long'
  });
  const day = fmt.format(d).toLowerCase();
  const map = {
    'domingo': 'Domingo',
    'segunda-feira': 'Segunda',
    'terça-feira': 'Terca',
    'quarta-feira': 'Quarta',
    'quinta-feira': 'Quinta',
    'sexta-feira': 'Sexta',
    'sábado': 'Sabado'
  };
  return map[day] || day;
}

function getISOWeek(dateStr) {
  const d = new Date(dateStr + 'T12:00:00Z');
  const target = new Date(d.valueOf());
  const dayNr = (d.getUTCDay() + 6) % 7;
  target.setUTCDate(target.getUTCDate() - dayNr + 3);
  const firstThursday = target.valueOf();
  target.setUTCMonth(0, 1);
  if (target.getUTCDay() !== 4) {
    target.setUTCMonth(0, 1 + ((4 - target.getUTCDay()) + 7) % 7);
  }
  return 1 + Math.ceil((firstThursday - target) / (7 * 24 * 3600 * 1000));
}

function getISOWeekYear(dateStr) {
  const d = new Date(dateStr + 'T12:00:00Z');
  const target = new Date(d.valueOf());
  target.setUTCDate(target.getUTCDate() - ((d.getUTCDay() + 6) % 7) + 3);
  return target.getUTCFullYear();
}

// ===== GET WEEK DAILY SUMMARIES (ULTIMOS 7 DIAS) =====
let weekSummariesBlock = '';
let weekSummariesArr = [];
let weekHasSummaries = false;
let totalScoreSum = 0;
let totalScoreCount = 0;
let avgScore = null;
let manualDaysCount = 0;
let patrolDaysCount = 0;
let uniqueDates = new Set();
let trend = 'N/A';

function extractDateFromEntry(entry) {
  const dateTag = (entry.tags || []).find(t => /^\d{4}-\d{2}-\d{2}$/.test(t));
  if (dateTag) return dateTag;
  const summary = entry.summary || '';
  const m1 = summary.match(/Daily summary (\d{4}-\d{2}-\d{2})/);
  if (m1) return m1[1];
  const m2 = summary.match(/Daily summary (\d{2})\/(\d{2})/);
  if (m2) return `2026-${m2[2]}-${m2[1]}`;
  if (entry.created_at) {
    const d = new Date(entry.created_at);
    d.setUTCDate(d.getUTCDate() - 1);
    return d.toISOString().slice(0, 10);
  }
  return 'data?';
}

function isManualSummary(entry) {
  return entry.source === 'Manual' && (entry.importance >= 2);
}

try {
  const summaryNode = $('Get Week Summary').first().json;
  if (summaryNode && summaryNode.found && summaryNode.entries && summaryNode.entries.length > 0) {
    weekHasSummaries = true;
    weekSummariesArr = summaryNode.entries;

    const manualOnly = summaryNode.entries.filter(isManualSummary);
    const patrolOnly = summaryNode.entries.filter(e => !isManualSummary(e));
    manualDaysCount = manualOnly.length;
    patrolDaysCount = patrolOnly.length;

    const compactLines = summaryNode.entries.map(entry => {
      const dateExtracted = extractDateFromEntry(entry);
      if (dateExtracted !== 'data?') uniqueDates.add(dateExtracted);
      const details = entry.details || '';
      const scoreMatch = details.match(/SCORE_?DO_?DIA:\s*(\d+(?:\.\d+)?)\s*\/\s*10/i);
      const score = scoreMatch ? scoreMatch[1] + '/10' : '-';
      if (scoreMatch) {
        totalScoreSum += parseFloat(scoreMatch[1]);
        totalScoreCount++;
      }
      const sourceTag = isManualSummary(entry) ? 'MANUAL' : 'PATROL';
      const summaryShort = (entry.summary || '').slice(0, 100);
      return `- ${dateExtracted} [${sourceTag}] | Score ${score} | ${summaryShort}`;
    });

    avgScore = totalScoreCount > 0 ? (totalScoreSum / totalScoreCount).toFixed(1) : null;

    if (totalScoreCount >= 3) {
      const scores = [];
      for (const entry of summaryNode.entries) {
        const m = (entry.details || '').match(/SCORE_?DO_?DIA:\s*(\d+(?:\.\d+)?)\s*\/\s*10/i);
        if (m) scores.push({ date: extractDateFromEntry(entry), score: parseFloat(m[1]) });
      }
      scores.sort((a, b) => a.date.localeCompare(b.date));
      const firstHalf = scores.slice(0, Math.floor(scores.length / 2));
      const secondHalf = scores.slice(Math.floor(scores.length / 2));
      const avg1 = firstHalf.reduce((s, x) => s + x.score, 0) / firstHalf.length;
      const avg2 = secondHalf.reduce((s, x) => s + x.score, 0) / secondHalf.length;
      const diff = avg2 - avg1;
      if (Math.abs(diff) < 0.5) trend = 'estavel';
      else if (diff > 0) trend = 'subindo';
      else trend = 'caindo';
    } else if (totalScoreCount === 0) {
      trend = 'sem dados (zero scores explicitos)';
    } else {
      trend = `amostra insuficiente (${totalScoreCount} score${totalScoreCount === 1 ? '' : 's'})`;
    }

    const manualDaysSet = new Set(manualOnly.map(extractDateFromEntry).filter(d => d !== 'data?'));
    const manualDaysWithFechamento = manualDaysSet.size;
    const diasSemFechamento = Math.max(0, 7 - manualDaysWithFechamento);

    weekSummariesBlock = `\n\nDAILY SUMMARIES ULTIMOS 7 DIAS (${manualDaysWithFechamento} dias com fechamento MANUAL, ${patrolDaysCount} entries PATROL automaticas):\n${compactLines.join('\n')}\n\nMEDIA DE SCORE: ${avgScore !== null ? avgScore + '/10 (' + totalScoreCount + ' scores)' : 'N/A — Ary nao registou SCORE DO DIA nos summaries'}\nTENDENCIA: ${trend}\nDIAS SEM FECHAMENTO MANUAL: ${diasSemFechamento}/7\n\nDETALHE COMPLETO DOS SUMMARIES (para analise de padroes):\n${summaryNode.entries.map(e => {
      const dateExtracted = extractDateFromEntry(e);
      const sourceTag = isManualSummary(e) ? 'MANUAL' : 'PATROL';
      return `=== ${dateExtracted} [${sourceTag}] ===\n${e.details || e.summary}`;
    }).join('\n\n')}\n`;
  } else {
    weekSummariesBlock = '\n\n⚠️ MEMORY READ FAILURE OR EMPTY: Get Week Summary retornou 0 entries para tag daily-summary nos ultimos 7 dias. Investigar pipeline.\n';
  }
} catch(e) {
  weekSummariesBlock = '\n\n(Erro a obter daily summaries da semana: ' + (e.message || 'unknown') + ')\n';
}

// ===== SEMANTIC SUMMARIES (NEW v3) =====
let semanticSummariesBlock = '';
let semanticHasResults = false;
let semanticResultsCount = 0;

try {
  const semanticNode = $('Get Week Summaries (Semantic)').first().json;
  const results = (semanticNode && semanticNode.results) || [];
  semanticResultsCount = results.length;

  if (results.length > 0) {
    semanticHasResults = true;

    const sevenDaysAgo = new Date();
    sevenDaysAgo.setUTCDate(sevenDaysAgo.getUTCDate() - 7);
    const cutoffDate = sevenDaysAgo.toISOString().slice(0, 10);

    const recentResults = results.filter(r => {
      if (!r.created_at) return false;
      return r.created_at >= cutoffDate;
    });

    const tagOnlyIds = new Set(weekSummariesArr.map(e => e.id || e.summary).filter(x => x));
    const semanticOnly = recentResults.filter(r => !tagOnlyIds.has(r.id || r.summary));

    if (semanticOnly.length > 0) {
      semanticSummariesBlock = `\n\nSUMMARIES SEMANTICOS ADICIONAIS (${semanticOnly.length} entries encontradas via similarity, NAO apanhadas por tag literal):\n${semanticOnly.slice(0, 10).map(r => {
        const date = r.created_at || 'unknown';
        const sim = r.similarity ? ` (sim: ${r.similarity})` : '';
        return `[${date}]${sim} ${r.summary}\n${(r.details || '').slice(0, 300)}`;
      }).join('\n---\n')}\n`;
    } else {
      semanticSummariesBlock = `\n\nSEMANTIC SEARCH: ${recentResults.length} resultados, todos ja apanhados pelo filtro tag literal. Coverage tag OK.\n`;
    }
  } else {
    semanticSummariesBlock = `\n\nSEMANTIC SEARCH: zero resultados (Brain Proxy pode estar down ou sem entries relevantes)\n`;
  }
} catch (e) {
  semanticSummariesBlock = `\n\n(Erro semantic search: ${e.message})\n`;
}

// ===== WEEK SNAPSHOTS DIFF (NEW v3) =====
let weeklyDiffSection = '';
let weekSnapshots = [];
let diffLeftRadar = [];
let diffEnteredRadar = [];
let diffRescheduled = [];
let diffStuckAllWeek = [];
let diffLeftDoneReal = [];
let diffLeftOther = [];

try {
  const snapshotsNode = $('Get Week Snapshots').all();
  weekSnapshots = snapshotsNode
    .map(i => i.json)
    .filter(s => s && s.details);
} catch (e) {
  weekSnapshots = [];
}

if (weekSnapshots.length >= 2) {
  try {
    const first = weekSnapshots[0];
    const last = weekSnapshots[weekSnapshots.length - 1];

    const firstDate = first.created_at ? first.created_at.substring(0, 10) : 'inicio';
    const lastDate = last.created_at ? last.created_at.substring(0, 10) : 'fim';

    const firstPayload = JSON.parse(first.details);
    const lastPayload = JSON.parse(last.details);

    const firstTasks = firstPayload.tasks || [];
    const lastTasks = lastPayload.tasks || [];

    const firstIds = new Set(firstTasks.map(t => t.id));
    const lastIds = new Set(lastTasks.map(t => t.id));
    const firstMap = new Map(firstTasks.map(t => [t.id, t]));

    diffLeftRadar = firstTasks.filter(t => !lastIds.has(t.id));
    diffEnteredRadar = lastTasks.filter(t => !firstIds.has(t.id));
    diffStuckAllWeek = lastTasks.filter(t => {
      const f = firstMap.get(t.id);
      return f && f.due_date === t.due_date && t.status !== 'Done';
    });
    diffRescheduled = lastTasks.filter(t => {
      const f = firstMap.get(t.id);
      return f && f.due_date !== t.due_date;
    });

    // PATCH 2026-05-30: decompor diffLeftRadar em done_real vs other (saiu da janela mas não Done)
    // Cross-reference com Tasks Concluidas (últimos 30d) para identificar done_real
    const doneItemsForXref = $('Tasks Concluidas').all().filter(i => {
      const props = i.json.properties || {};
      return Object.keys(props).length > 0;
    });
    const doneIds = new Set(doneItemsForXref.map(i => i.json.id));

    diffLeftDoneReal = diffLeftRadar.filter(t => doneIds.has(t.id));
    diffLeftOther = diffLeftRadar.filter(t => !doneIds.has(t.id));

    const lines = [];
    lines.push(`MOVIMENTO DA SEMANA (snapshots ${firstDate} → ${lastDate}, ${weekSnapshots.length} pontos):`);
    lines.push(`Backlog total Notion: ${firstPayload.total_pending_in_notion || firstTasks.length} → ${lastPayload.total_pending_in_notion || lastTasks.length}`);
    lines.push(`Relevantes (snapshot filter): ${firstTasks.length} → ${lastTasks.length}`);
    lines.push(`Saidas: ${diffLeftRadar.length} (${diffLeftDoneReal.length} Done reais + ${diffLeftOther.length} saiu da janela sem Done) | Entradas: ${diffEnteredRadar.length} | Reagendadas: ${diffRescheduled.length} | Stuck toda semana: ${diffStuckAllWeek.length}`);

    if (diffStuckAllWeek.length > 0) {
      lines.push(`\nSTUCK ALL WEEK (nao mexido em 7 dias, mesmo due_date inicio e fim):`);
      diffStuckAllWeek.slice(0, 10).forEach(t => {
        const prio = t.priority === 'Alta' ? '🔴' : t.priority === 'Media' ? '🟡' : '⚪';
        const due = t.due_date ? ` (due: ${t.due_date})` : ' (sem data)';
        lines.push(`  ${prio} ${t.name}${due}`);
      });
      if (diffStuckAllWeek.length > 10) lines.push(`  ... +${diffStuckAllWeek.length - 10} mais`);
    }

    if (diffRescheduled.length > 0) {
      lines.push(`\nREAGENDADAS (${diffRescheduled.length} tasks com due_date alterado):`);
      diffRescheduled.slice(0, 5).forEach(t => {
        const f = firstMap.get(t.id);
        const oldD = f.due_date || '(sem)';
        const newD = t.due_date || '(sem)';
        lines.push(`  - ${t.name}: ${oldD} → ${newD}`);
      });
      if (diffRescheduled.length > 5) lines.push(`  ... +${diffRescheduled.length - 5} mais`);
    }

    if (diffRescheduled.length > 5) {
      lines.push(`\n⚠️ ALERTA PROCRASTINACAO: ${diffRescheduled.length} tasks reagendadas esta semana.`);
    }

    if (diffEnteredRadar.length > diffLeftRadar.length + 5) {
      lines.push(`\n⚠️ ALERTA BACKLOG INFLATION: ${diffEnteredRadar.length} entradas vs ${diffLeftRadar.length} saidas (${diffEnteredRadar.length - diffLeftRadar.length} liquido +).`);
    }

    weeklyDiffSection = '\n\n' + lines.join('\n') + '\n';
  } catch (e) {
    weeklyDiffSection = `\n\n(Erro a calcular diff semanal: ${e.message})\n`;
  }
} else {
  weeklyDiffSection = `\n\nMOVIMENTO DA SEMANA: ${weekSnapshots.length} snapshots disponiveis (precisa >=2 para diff). Sistema acabou de iniciar — diff completo disponivel semana que vem.\n`;
}

// ===== BUILD PROJECT LOOKUP MAP =====
const projectItems = $('Active Projects').all().filter(i => {
  const props = i.json.properties || {};
  return Object.keys(props).length > 0;
});

const projectMap = {};
for (const p of projectItems) {
  const id = p.json.id;
  const name = getTaskName(p);
  const type = getProjectType(p);
  projectMap[id] = { name, type };
}

function getProjectName(item) {
  const id = getProjectId(item);
  if (!id) return '';
  if (projectMap[id]) return projectMap[id].name;
  return '(unknown project)';
}

// ===== DATE REFERENCES =====
const today = getTodayLisbon();
const weekday = getWeekdayLisbon(today);
const weekNumber = getISOWeek(today);
const weekYear = getISOWeekYear(today);

const [ty, tm, td] = today.split('-');
const todayDisplay = `${td}/${tm}/${ty}`;

// ===== TASKS CONCLUIDAS =====
const doneItems = $('Tasks Concluidas').all().filter(i => {
  const props = i.json.properties || {};
  return Object.keys(props).length > 0;
});
const done = doneItems.map(i => {
  const name = getTaskName(i);
  const due = getDueDate(i);
  const project = getProjectName(i);
  const tags = getTags(i);
  const ctx = getContext(tags);
  const projectTag = project ? ` [${project}]` : '';
  const ctxTag = ctx ? ` ${ctx}` : '';
  const dueTag = due ? ` (${due})` : '';
  return `${name}${projectTag}${ctxTag}${dueTag}`;
}).join('\n');
const doneCount = doneItems.length;

// ===== TASKS ATRASADAS =====
// PATCH 2026-05-30: filtro estrito Due < today (Notion node devolve inclusivo, separamos aqui)
const overdueRawItems = $('Tasks Atrasadas').all().filter(i => {
  const props = i.json.properties || {};
  return Object.keys(props).length > 0;
});

const overdueItems = overdueRawItems.filter(i => {
  const due = getDueDate(i);
  return due && due < today;
});
const dueTodayItems = overdueRawItems.filter(i => {
  const due = getDueDate(i);
  return due && due === today;
});

const overdue = overdueItems.map(i => {
  const name = getTaskName(i);
  const due = getDueDate(i);
  const project = getProjectName(i);
  const tags = getTags(i);
  const prio = tags.includes('Prioridade Alta') ? '🔴'
    : (tags.includes('Prioridade Média') || tags.includes('Prioridade Media')) ? '🟡'
    : '⚪';
  const ctx = getContext(tags);
  const dep = getDependency(tags);
  const flags = [ctx, dep].filter(x => x).join(' ');
  const projectTag = project ? ` [${project}]` : '';
  const flagsTag = flags ? ` ${flags}` : '';
  const dueD = new Date(due + 'T12:00:00Z');
  const todayD = new Date(today + 'T12:00:00Z');
  const daysOverdue = Math.floor((todayD - dueD) / (1000 * 60 * 60 * 24));
  const daysTag = daysOverdue > 0 ? ` (${daysOverdue}d)` : '';
  return `${prio} ${name}${projectTag}${flagsTag} (due: ${due})${daysTag}`;
}).join('\n');
const overdueCount = overdueItems.length;
const dueTodayCount = dueTodayItems.length;

const dependencyItems = overdueItems.filter(i => getTags(i).includes('Dependo de Terceiros'));
const dependencyCount = dependencyItems.length;
const ownOverdueCount = overdueCount - dependencyCount;

// ===== TASKS DUE WEEK =====
const dueWeekItems = $('Tasks Criadas Semana').all().filter(i => {
  const props = i.json.properties || {};
  return Object.keys(props).length > 0;
});
const dueWeekCount = dueWeekItems.length;

// ===== ACTIVE PROJECTS =====
const projects = projectItems.map(i => {
  const name = getTaskName(i);
  const type = getProjectType(i);
  const icon = type === 'Client' ? '🟢'
    : type === 'Prospect' ? '🟡'
    : type === 'Closed' ? '⚫'
    : '⚪';
  return `${icon} ${name}${type ? ' (' + type + ')' : ''}`;
}).join('\n');

const clientCount = projectItems.filter(p => getProjectType(p) === 'Client').length;
const prospectCount = projectItems.filter(p => getProjectType(p) === 'Prospect').length;

// ===== PROMPT =====
const prompt = `Hoje e ${todayDisplay}, ${weekday}. SWOT Semanal para Ary Ribeiro.

CONTEXTO: Consultor IA, 3 verticais: TJ (advogados BR R$2.997/mes), TM (clinicas BR R$2.997/mes), CL (imobiliarias PT E497/mes). Meta Q2: E12.857 trimestral (~E4.286/mes). Revenue actual: E0. Foco actual: construcao da maquina (consistencia de conteudos). Regra: NAO cobrar Sales/pipeline ate 11 Jun 2026.

PROJECTOS ACTIVOS (${projectItems.length} total: ${clientCount} Client, ${prospectCount} Prospect):
${projects || '(nenhum projecto activo)'}
${weekSummariesBlock}
${semanticSummariesBlock}
${weeklyDiffSection}
TASKS NOTION CONCLUIDAS ULTIMOS 30 DIAS (${doneCount}):
${done || '(nenhuma task concluida)'}

TASKS ATRASADAS (${overdueCount} vencidas, due <= hoje, ultimos 30d${dependencyCount > 0 ? '; ' + dependencyCount + ' a aguardar terceiros' : ''}):
${overdue || '(nenhuma task atrasada)'}

VOLUME: ${dueWeekCount} tasks com Due Date na semana passada

LEGENDA: 🔴 Alta | 🟡 Media | ⚪ Baixa/sem | 🇧🇷 Brasil | 🇵🇹 Portugal | ⏸️ Dependo de terceiros | 🟢 Client | 🟡 Prospect | ⚫ Closed

ANALISA estes dados e gera um SWOT estrategico:

═══ HARD CONSTRAINTS ═══

HC1 - DIFF SEMANAL: SEMANTICA E LIMITACOES (v4 reforcado):
A seccao MOVIMENTO DA SEMANA mostra diff entre snapshot Notion no inicio e fim da semana.
DECOMPOSICAO IMPORTANTE de "Saidas" (diffLeftRadar):
- diffLeftDoneReal=${diffLeftDoneReal.length}: tasks que SAIRAM porque foram marcadas Done (eliminacao real).
- diffLeftOther=${diffLeftOther.length}: tasks que sairam da janela relevante MAS nao foram Done.
  Possiveis razoes: rescheduled para >14d, due_date passou para <-7d sem fechar, ou apagadas.
  NAO chamar a estas "eliminadas" ou "concluidas" — chamar "sairam da janela sem Done".

