// ===== HELPERS =====
function getTaskName(item) {
  const props = item.json.properties || {};
  const nameProps = ['Name', 'Task', 'Title', 'name', 'title'];
  for (const key of nameProps) {
    if (props[key] && props[key].title && Array.isArray(props[key].title) && props[key].title.length > 0) {
      return props[key].title.map(t => t.plain_text || '').join('').trim();
    }
  }
  for (const key of Object.keys(props)) {
    const p = props[key];
    if (p && p.type === 'title' && Array.isArray(p.title) && p.title.length > 0) {
      return p.title.map(t => t.plain_text || '').join('').trim();
    }
  }
  return '(sem nome)';
}

function getTags(item) {
  const props = item.json.properties || {};
  const tagProps = ['Tags', 'Tag', 'Labels'];
  for (const key of tagProps) {
    if (props[key]) {
      if (props[key].multi_select) return props[key].multi_select.map(t => t.name);
      if (props[key].select && props[key].select.name) return [props[key].select.name];
    }
  }
  return [];
}

function getDueDate(item) {
  const props = item.json.properties || {};
  const dateProps = ['Due Date', 'Due', 'Date', 'Deadline'];
  for (const key of dateProps) {
    if (props[key] && props[key].date && props[key].date.start) {
      return props[key].date.start;
    }
  }
  return '';
}

function getProjectId(item) {
  const props = item.json.properties || {};
  const projProps = ['Project', 'Projects'];
  for (const key of projProps) {
    if (props[key] && props[key].relation && props[key].relation.length > 0) {
      return props[key].relation[0].id;
    }
  }
  return '';
}

function getProjectType(item) {
  const props = item.json.properties || {};
  const typeProps = ['Type', 'Tipo', 'Category'];
  for (const key of typeProps) {
    if (props[key]) {
      if (props[key].select && props[key].select.name) return props[key].select.name;
    }
  }
  return '';
}

function getContext(tags) {
  if (tags.includes('Brasil')) return '🇧🇷';
  if (tags.includes('Portugal')) return '🇵🇹';
  return '';
}

function getDependency(tags) {
  if (tags.includes('Dependo de Terceiros')) return '⏸️';
  return '';
}

function getTodayLisbon() {
  const now = new Date();
  return new Intl.DateTimeFormat('en-CA', {
    timeZone: 'Europe/Lisbon',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit'
  }).format(now);
}

function getWeekdayLisbon(dateStr) {
  const d = new Date(dateStr + 'T12:00:00Z');
  const fmt = new Intl.DateTimeFormat('pt-PT', {
    timeZone: 'Europe/Lisbon',
    weekday: 'long'
  });
  const day = fmt.format(d).toLowerCase();
  const map = {
    'domingo': 'Domingo',
    'segunda-feira': 'Segunda',
    'terça-feira': 'Terca',
    'quarta-feira': 'Quarta',
    'quinta-feira': 'Quinta',
    'sexta-feira': 'Sexta',
    'sábado': 'Sabado'
  };
  return map[day] || day;
}

function getISOWeek(dateStr) {
  const d = new Date(dateStr + 'T12:00:00Z');
  const target = new Date(d.valueOf());
  const dayNr = (d.getUTCDay() + 6) % 7;
  target.setUTCDate(target.getUTCDate() - dayNr + 3);
  const firstThursday = target.valueOf();
  target.setUTCMonth(0, 1);
  if (target.getUTCDay() !== 4) {
    target.setUTCMonth(0, 1 + ((4 - target.getUTCDay()) + 7) % 7);
  }
  return 1 + Math.ceil((firstThursday - target) / (7 * 24 * 3600 * 1000));
}

function getISOWeekYear(dateStr) {
  const d = new Date(dateStr + 'T12:00:00Z');
  const target = new Date(d.valueOf());
  target.setUTCDate(target.getUTCDate() - ((d.getUTCDay() + 6) % 7) + 3);
  return target.getUTCFullYear();
}

// ===== GET WEEK DAILY SUMMARIES (ULTIMOS 7 DIAS) =====
let weekSummariesBlock = '';
let weekSummariesArr = [];
let weekHasSummaries = false;
let totalScoreSum = 0;
let totalScoreCount = 0;
let avgScore = null;
let manualDaysCount = 0;
let patrolDaysCount = 0;
let uniqueDates = new Set();
let trend = 'N/A';

function extractDateFromEntry(entry) {
  const dateTag = (entry.tags || []).find(t => /^\d{4}-\d{2}-\d{2}$/.test(t));
  if (dateTag) return dateTag;
  const summary = entry.summary || '';
  const m1 = summary.match(/Daily summary (\d{4}-\d{2}-\d{2})/);
  if (m1) return m1[1];
  const m2 = summary.match(/Daily summary (\d{2})\/(\d{2})/);
  if (m2) return `2026-${m2[2]}-${m2[1]}`;
  if (entry.created_at) {
    const d = new Date(entry.created_at);
    d.setUTCDate(d.getUTCDate() - 1);
    return d.toISOString().slice(0, 10);
  }
  return 'data?';
}

function isManualSummary(entry) {
  return entry.source === 'Manual' && (entry.importance >= 2);
}

try {
  const summaryNode = $('Get Week Summary').first().json;
  if (summaryNode && summaryNode.found && summaryNode.entries && summaryNode.entries.length > 0) {
    weekHasSummaries = true;
    weekSummariesArr = summaryNode.entries;

    const manualOnly = summaryNode.entries.filter(isManualSummary);
    const patrolOnly = summaryNode.entries.filter(e => !isManualSummary(e));
    manualDaysCount = manualOnly.length;
    patrolDaysCount = patrolOnly.length;

    const compactLines = summaryNode.entries.map(entry => {
      const dateExtracted = extractDateFromEntry(entry);
      if (dateExtracted !== 'data?') uniqueDates.add(dateExtracted);
      const details = entry.details || '';
      const scoreMatch = details.match(/SCORE_?DO_?DIA:\s*(\d+(?:\.\d+)?)\s*\/\s*10/i);
      const score = scoreMatch ? scoreMatch[1] + '/10' : '-';
      if (scoreMatch) {
        totalScoreSum += parseFloat(scoreMatch[1]);
        totalScoreCount++;
      }
      const sourceTag = isManualSummary(entry) ? 'MANUAL' : 'PATROL';
      const summaryShort = (entry.summary || '').slice(0, 100);
      return `- ${dateExtracted} [${sourceTag}] | Score ${score} | ${summaryShort}`;
    });

    avgScore = totalScoreCount > 0 ? (totalScoreSum / totalScoreCount).toFixed(1) : null;

    if (totalScoreCount >= 3) {
      const scores = [];
      for (const entry of summaryNode.entries) {
        const m = (entry.details || '').match(/SCORE_?DO_?DIA:\s*(\d+(?:\.\d+)?)\s*\/\s*10/i);
        if (m) scores.push({ date: extractDateFromEntry(entry), score: parseFloat(m[1]) });
      }
      scores.sort((a, b) => a.date.localeCompare(b.date));
      const firstHalf = scores.slice(0, Math.floor(scores.length / 2));
      const secondHalf = scores.slice(Math.floor(scores.length / 2));
      const avg1 = firstHalf.reduce((s, x) => s + x.score, 0) / firstHalf.length;
      const avg2 = secondHalf.reduce((s, x) => s + x.score, 0) / secondHalf.length;
      const diff = avg2 - avg1;
      if (Math.abs(diff) < 0.5) trend = 'estavel';
      else if (diff > 0) trend = 'subindo';
      else trend = 'caindo';
    } else if (totalScoreCount === 0) {
      trend = 'sem dados (zero scores explicitos)';
    } else {
      trend = `amostra insuficiente (${totalScoreCount} score${totalScoreCount === 1 ? '' : 's'})`;
    }

    const manualDaysSet = new Set(manualOnly.map(extractDateFromEntry).filter(d => d !== 'data?'));
    const manualDaysWithFechamento = manualDaysSet.size;
    const diasSemFechamento = Math.max(0, 7 - manualDaysWithFechamento);

    weekSummariesBlock = `\n\nDAILY SUMMARIES ULTIMOS 7 DIAS (${manualDaysWithFechamento} dias com fechamento MANUAL, ${patrolDaysCount} entries PATROL automaticas):\n${compactLines.join('\n')}\n\nMEDIA DE SCORE: ${avgScore !== null ? avgScore + '/10 (' + totalScoreCount + ' scores)' : 'N/A — Ary nao registou SCORE DO DIA nos summaries'}\nTENDENCIA: ${trend}\nDIAS SEM FECHAMENTO MANUAL: ${diasSemFechamento}/7\n\nDETALHE COMPLETO DOS SUMMARIES (para analise de padroes):\n${summaryNode.entries.map(e => {
      const dateExtracted = extractDateFromEntry(e);
      const sourceTag = isManualSummary(e) ? 'MANUAL' : 'PATROL';
      return `=== ${dateExtracted} [${sourceTag}] ===\n${e.details || e.summary}`;
    }).join('\n\n')}\n`;
  } else {
    weekSummariesBlock = '\n\n⚠️ MEMORY READ FAILURE OR EMPTY: Get Week Summary retornou 0 entries para tag daily-summary nos ultimos 7 dias. Investigar pipeline.\n';
  }
} catch(e) {
  weekSummariesBlock = '\n\n(Erro a obter daily summaries da semana: ' + (e.message || 'unknown') + ')\n';
}

